	@Test
	void rebuildsDegradedGuaranteeOnRestartAfterPotentiallyRestoringDelete(@TempDir File dataDir) {
		IRI predicate = VF.createIRI("http://example.com/value");
		IRI firstSubject = VF.createIRI("http://example.com/s1");
		IRI secondSubject = VF.createIRI("http://example.com/s2");
		Literal canonical = VF.createLiteral("7", XSD.INT);
		Literal leadingZero = VF.createLiteral("007", XSD.INT);

		SailRepository repository = repository(dataDir);
		try {
			try (RepositoryConnection connection = repository.getConnection()) {
				connection.add(firstSubject, predicate, canonical);
			}
			RdfTermDomain canonicalGuarantee = guarantee(repository, predicate);
			assertHas(canonicalGuarantee, RdfTermDomain.Fact.CANONICAL_INTEGER);
			assertHas(canonicalGuarantee, RdfTermDomain.Fact.NUMBER);
			assertHasDatatype(canonicalGuarantee, CoreDatatype.XSD.INT);

			try (RepositoryConnection connection = repository.getConnection()) {
				connection.add(secondSubject, predicate, leadingZero);
			}
			RdfTermDomain numericGuarantee = guarantee(repository, predicate);
			assertHas(numericGuarantee, RdfTermDomain.Fact.NUMBER);
			assertFalse(numericGuarantee.has(RdfTermDomain.Fact.CANONICAL_INTEGER));
			assertHasDatatype(numericGuarantee, CoreDatatype.XSD.INT);

			try (RepositoryConnection connection = repository.getConnection()) {
				connection.remove(secondSubject, predicate, leadingZero);
			}
			numericGuarantee = guarantee(repository, predicate);
			assertHas(numericGuarantee, RdfTermDomain.Fact.NUMBER);
			assertFalse(numericGuarantee.has(RdfTermDomain.Fact.CANONICAL_INTEGER));
		} finally {
			repository.shutDown();
		}

		SailRepository reopened = repository(dataDir);
		try {
			assertHas(guarantee(reopened, predicate), RdfTermDomain.Fact.CANONICAL_INTEGER);
		} finally {
			reopened.shutDown();
		}
	}

