	@Test
	void recordsOverlappingResourceLiteralLanguageAndDatatypeFacts(@TempDir File dataDir) {
		IRI iriPredicate = VF.createIRI("http://example.com/iri");
		IRI langPredicate = VF.createIRI("http://example.com/lang");
		IRI stringPredicate = VF.createIRI("http://example.com/string");
		IRI subject = VF.createIRI("http://example.com/s1");

		SailRepository repository = repository(dataDir);
		try {
			try (RepositoryConnection connection = repository.getConnection()) {
				connection.add(subject, iriPredicate, VF.createIRI("http://example.com/object"));
				connection.add(subject, langPredicate, VF.createLiteral("text", "en"));
				connection.add(subject, stringPredicate, VF.createLiteral("text"));
			}

			RdfTermDomain iriGuarantee = guarantee(repository, iriPredicate);
			assertHas(iriGuarantee, RdfTermDomain.Fact.IRI);
			assertFalse(iriGuarantee.has(RdfTermDomain.Fact.LITERAL));

			RdfTermDomain langGuarantee = guarantee(repository, langPredicate);
			assertHas(langGuarantee, RdfTermDomain.Fact.LITERAL);
			assertHas(langGuarantee, RdfTermDomain.Fact.LITERAL_WITH_LANGUAGE);
			assertFalse(langGuarantee.has(RdfTermDomain.Fact.LITERAL_WITHOUT_LANGUAGE));

			RdfTermDomain stringGuarantee = guarantee(repository, stringPredicate);
			assertHas(stringGuarantee, RdfTermDomain.Fact.LITERAL);
			assertHas(stringGuarantee, RdfTermDomain.Fact.LITERAL_WITHOUT_LANGUAGE);
			assertHasDatatype(stringGuarantee, CoreDatatype.XSD.STRING);
		} finally {
			repository.shutDown();
		}
	}

	private static SailRepository repository(File dataDir) {
		LmdbStoreConfig config = new LmdbStoreConfig("spoc,posc")
				.setOptimizerSamplingEnabled(false)
				.setBackgroundRawSamplingMaxMillisPerCycle(0L);
		SailRepository repository = new SailRepository(new LmdbStore(dataDir, config));
		repository.init();
		return repository;
	}

	private static RdfTermDomain guarantee(SailRepository repository, IRI predicate) {
		LmdbStore sail = (LmdbStore) repository.getSail();
		LmdbPredicateObjectDomainSource source = (LmdbPredicateObjectDomainSource) sail.getBackingStore()
				.getEvaluationStatistics();
		return source.getRdfTermDomain(predicate);
	}

	private static void makeLmdbOptimizerReady(SailRepository repository) throws InterruptedException {
		LmdbStore sail = (LmdbStore) repository.getSail();
		SketchBasedJoinEstimator estimator = sail.getBackingStore()
				.getSketchBasedJoinEstimator();
		estimator.stop();
		estimator.rebuild();
		assertTrue(estimator.isReadyNonBlocking());
		assertTrue(sail.awaitSketchesReady(1, TimeUnit.SECONDS));
	}

	private static OptimizerSnapshot explainOptimized(SailRepository repository, String query) {
		try (RepositoryConnection connection = repository.getConnection()) {
			Explanation explanation = connection.prepareTupleQuery(query)
					.explain(Explanation.Level.Optimized);
			return new OptimizerSnapshot(
					explanation.toString(),
					new TupleExprIRRenderer().render((TupleExpr) explanation.tupleExpr()));
		}
	}

	private record OptimizerSnapshot(String plan, String renderedQuery) {
	}

	private static int countResults(SailRepository repository, String query) {
		try (RepositoryConnection connection = repository.getConnection();
				TupleQueryResult result = connection.prepareTupleQuery(query).evaluate()) {
			int count = 0;
			while (result.hasNext()) {
				result.next();
				count++;
			}
			return count;
		}
	}

	private static void assertHas(RdfTermDomain guarantee, RdfTermDomain.Fact fact) {
		assertTrue(guarantee.has(fact), () -> "Expected " + guarantee + " to contain " + fact);
	}

	private static void assertHasDatatype(RdfTermDomain guarantee, CoreDatatype.XSD datatype) {
		assertTrue(guarantee.hasDatatype(datatype), () -> "Expected " + guarantee + " to contain " + datatype);
	}

	private static void downgradeGuaranteeMetadata(File dataDir) {
		StoreProperties properties = new StoreProperties(dataDir);
		properties.load();
		properties.setRdfTermDomainsVersion("stale");
		properties.save();
	}
